server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate /etc/nginx/ssl/server.crt;
    ssl_certificate_key /etc/nginx/ssl/server.key;

    # Dev branch at /dev/
    location /dev/ {
        alias /var/www/dev/;
        index index.html;
    }

    # Main branch at /
    location / {
        root /var/www/main;
        index index.html;
    }
}

